/* Good for: Look up biome RGB from generated tint table.
 * Callers: biome_tint.c (same file).
 */

static void lc_biome_rgb_lookup(const uint8_t *table, int32_t biome_id, uint8_t *r, uint8_t *g, uint8_t *b) {
  if (biome_id < 0 || biome_id > LC_BIOME_ID_MAX) biome_id = LC_PLAINS_BIOME_ID;
  const uint8_t *p = &table[(size_t)biome_id * 3];
  *r = p[0];
  *g = p[1];
  *b = p[2];
}

static void lc_tint_ratio_rgb(uint8_t *r, uint8_t *g, uint8_t *b,
                                const uint8_t ref[3], const uint8_t tint[3]) {
  unsigned br = ref[0] ? ref[0] : 1u;
  unsigned bg = ref[1] ? ref[1] : 1u;
  unsigned bb = ref[2] ? ref[2] : 1u;
  *r = (uint8_t)(((unsigned)*r * tint[0]) / br);
  *g = (uint8_t)(((unsigned)*g * tint[1]) / bg);
  *b = (uint8_t)(((unsigned)*b * tint[2]) / bb);
}
/* Good for: Apply biome grass/foliage tint to map RGB.
 * Callers: map_png.c.
 */

void lc_map_rgb_apply_biome_tint(int32_t state_id, int32_t biome_id, uint8_t *r, uint8_t *g, uint8_t *b) {
  if (!r || !g || !b || state_id < 0 || state_id > LC_STATE_MAP_MAX) return;
  uint8_t kind = LC_STATE_TINT_KIND[state_id];
  if (kind == 1) {
    /* grass_block top RGB is baked as plains; use biome grass color directly. */
    lc_biome_rgb_lookup(LC_BIOME_GRASS_RGB, biome_id, r, g, b);
  } else if (kind == 2) {
    uint8_t tr, tg, tb, tint[3];
    lc_biome_rgb_lookup(LC_BIOME_FOLIAGE_RGB, biome_id, &tr, &tg, &tb);
    tint[0] = tr;
    tint[1] = tg;
    tint[2] = tb;
    lc_tint_ratio_rgb(r, g, b, LC_PLAINS_FOLIAGE_RGB, tint);
  }
}
